    """
    count = 0
    for n in nums:
        if abs(n) > 10 and abs(n) % 10!= 0 and abs(n) % 10!= 8 and abs(n) % 10!= 6 and abs(n) % 10!= 4 and abs(n) % 10!= 2 and abs(n) % 10!= 1:
            count += 1
        elif n < 0 and abs(n) % 10!= 8 and abs(n) % 10!= 6 and abs(n) % 10!= 4 and abs(n) % 10!= 2 and abs(n) % 10!= 1:
            count += 1
        elif n > 0 and abs(n) % 10!= 8 and abs(n) % 10!= 6 and abs(n) % 10!= 4 and abs(n) % 10!= 2 and abs(n) % 10!= 1:
            count += 1
        else:
            pass
    return count

